"""
Serializers for PyArrow and pandas conversions for Databricks edge features.
See `pyspark.serializers` for more details.
"""
import math
import itertools

from pyspark.sql.pandas.serializers import (
    ArrowStreamPandasUDFSerializer,
    ArrowStreamSerializer,
    CogroupPandasUDFSerializer,
    read_int,
    write_int,
    SpecialLengths,
)
from pyspark.sql.pandas.utils import estimate_pandas_convert_as_arrow_size
from pyspark.sql.conversion import ArrowArrayToPandasConversion, PandasToArrowConversion
from pyspark.sql.types import StructType, StructField


def slice_pandas_frame(series, pandas_max_bytes_per_slice):
    """
    Slice each pandas DataFrame into smaller chunks based on estimated size.

    Parameters
    ----------
    series : Iterator[(pd.DataFrame, arrow_type)]
        Iterator of (DataFrame, arrow_type) tuples to slice
    pandas_max_bytes_per_slice : int
        Maximum bytes per slice

    Yields
    ------
    Iterator[(pd.DataFrame, arrow_type)]
        Sliced DataFrames with their arrow types
    """
    for frame, t in series:
        # The logic here mimics the conversion from pandas to Spark DataFrame.
        estimated_data_size = estimate_pandas_convert_as_arrow_size(frame)
        num_slices = math.ceil(estimated_data_size / pandas_max_bytes_per_slice)
        length = len(frame)
        num_slices = min(num_slices, length)
        yield (
            (frame.iloc[i * length // num_slices : (i + 1) * length // num_slices], t)
            for i in range(0, num_slices)
        )


class GroupUDFSerializer(ArrowStreamPandasUDFSerializer):
    """
    Serializer for SQL_GROUPED_MAP_PANDAS_UDF with Databricks edge optimizations.

    This serializer extends ArrowStreamPandasUDFSerializer with:
    - load_stream returns Iterator[Iterator[pa.RecordBatch]] to match GroupPandasUDFSerializer API
    - dump_stream applies DataFrame slicing for better memory management
    """

    def __init__(
        self,
        *,
        timezone,
        safecheck,
        assign_cols_by_name,
        prefer_int_ext_dtype=False,
        df_for_struct=False,
        max_prefetch=0,
        timely_flush_enabled=True,
        timely_flush_timeout_ms=100,
        max_bytes=-1,
        arrow_cast=False,
        int_to_decimal_coercion_enabled=False,
    ):
        super(GroupUDFSerializer, self).__init__(
            timezone=timezone,
            safecheck=safecheck,
            assign_cols_by_name=assign_cols_by_name,
            df_for_struct=df_for_struct,
            max_prefetch=max_prefetch,
            timely_flush_enabled=timely_flush_enabled,
            timely_flush_timeout_ms=timely_flush_timeout_ms,
            prefer_int_ext_dtype=prefer_int_ext_dtype,
            arrow_cast=arrow_cast,
            int_to_decimal_coercion_enabled=int_to_decimal_coercion_enabled,
        )
        self.max_bytes = max_bytes

    def load_stream(self, stream):
        """
        Deserialize each grouped ArrowRecordBatches and yield raw Iterator[pa.RecordBatch].
        Each outer iterator element represents a group, matching GroupPandasUDFSerializer API.

        The Arrow-to-pandas conversion is handled by the mapper in worker.py, not here.

        +------+-----------------+------+------+-----------------+------+------+--------------------
        |Schema|            Batch| Batch|Schema|            Batch| Batch|Schema|           Batch ...
        +------+-----------------+------+------+-----------------+------+------+--------------------
        |    Arrow Streaming Format     |    Arrow Streaming Format     |    Arrow Streaming Form...

        """
        should_read_more = read_int(stream) == 1

        while should_read_more:
            batches = ArrowStreamSerializer.load_stream(self, stream)
            yield batches
            # Ensure all batches are consumed before reading the next group marker
            for _ in batches:
                pass
            should_read_more = read_int(stream) == 1

    def dump_stream(self, iterator, stream, timely_flush_enabled=True, timely_flush_timeout_ms=100):
        """
        Serialize each pandas DataFrame after applying the function into sized batches.
        It is different from OSS side because it slices each pandas DataFrame into smaller
        Arrow batches. For example, the pandas DataFrame outputs below are converted into
        one complete Arrow streaming format.

        Input format: Iterator[Iterator[[(df, arrow_type)]]] (from mapper)
        - Outer iterator: groups
        - Inner iterator: result batches per group
        - Each element: [(df, arrow_type)]

               +------------------------+------------------------+------------------------
               |pd.DF (by k1) v1, v2, v3|pd.DF (by k2) v1, v2, v3|                     ...
               +------------------------+------------------------+------------------------

        +------+--------+--------+------+--------+--------+------+--------+--------+------
        |Schema|   Batch|   Batch| Batch|   Batch|   Batch| Batch|   Batch|   Batch|   ...
        +------+--------+--------+------+--------+--------+------+--------+--------+------
        |                                 Arrow Streaming Format                       ...

        """
        assert self.max_bytes > 0

        def init_stream_yield_batches():
            should_write_start_length = True
            # Flatten Iterator[Iterator[[(df, arrow_type)]]] to Iterator[(df, arrow_type)]
            # First flatten: Iterator[Iterator[[(df, arrow_type)]]] -> Iterator[[(df, arrow_type)]]
            flattened_once = (batch for group_iter in iterator for batch in group_iter)
            # Second flatten: Iterator[[(df, arrow_type)]] -> Iterator[(df, arrow_type)]
            frames = (item for batch in flattened_once for item in batch)
            # Apply slicing to each (df, arrow_type)
            slices = (slice_pandas_frame(iter([frame_tuple]), self.max_bytes) for frame_tuple in frames)
            slices = itertools.chain(*itertools.chain(*slices))

            def create_batch(sliced):
                df, spark_type = sliced
                schema = StructType([StructField("_0", spark_type)])
                return PandasToArrowConversion.convert(
                    [df],
                    schema,
                    timezone=self._timezone,
                    safecheck=self._safecheck,
                    arrow_cast=self._arrow_cast,
                    prefers_large_types=self._prefers_large_types,
                    assign_cols_by_name=self._assign_cols_by_name,
                    int_to_decimal_coercion_enabled=self._int_to_decimal_coercion_enabled,
                )

            batches = (create_batch(sliced) for sliced in slices)
            for batch in batches:
                if should_write_start_length:
                    write_int(SpecialLengths.START_ARROW_STREAM, stream)
                    should_write_start_length = False
                yield batch

        return ArrowStreamSerializer.dump_stream(
            self,
            init_stream_yield_batches(),
            stream,
            timely_flush_enabled=self.timely_flush_enabled,
            timely_flush_timeout_ms=self.timely_flush_timeout_ms,
        )


class DatabricksCogroupPandasUDFSerializer(CogroupPandasUDFSerializer):
    """
    Serializer for SQL_COGROUPED_MAP_PANDAS_UDF with Databricks edge optimizations.

    This serializer extends CogroupPandasUDFSerializer with:
    - dump_stream applies DataFrame slicing for better memory management
    """

    def __init__(
        self,
        *,
        timezone,
        safecheck,
        assign_cols_by_name,
        prefer_int_ext_dtype=False,
        df_for_struct=False,
        max_prefetch=0,
        timely_flush_enabled=True,
        timely_flush_timeout_ms=100,
        max_bytes=-1,
        arrow_cast=False,
        int_to_decimal_coercion_enabled=False,
    ):
        super(DatabricksCogroupPandasUDFSerializer, self).__init__(
            timezone=timezone,
            safecheck=safecheck,
            assign_cols_by_name=assign_cols_by_name,
            df_for_struct=df_for_struct,
            max_prefetch=max_prefetch,
            timely_flush_enabled=timely_flush_enabled,
            timely_flush_timeout_ms=timely_flush_timeout_ms,
            prefer_int_ext_dtype=prefer_int_ext_dtype,
            arrow_cast=arrow_cast,
            int_to_decimal_coercion_enabled=int_to_decimal_coercion_enabled,
        )
        self.max_bytes = max_bytes

    def dump_stream(self, iterator, stream, timely_flush_enabled=True, timely_flush_timeout_ms=100):
        """
        Serialize each pandas DataFrame after applying the function into sized batches.
        For cogroup, the mapper returns Iterator[[(df, arrow_type)]].

        Input format: Iterator[[(df, arrow_type)]] (from cogroup mapper)
        """
        assert self.max_bytes > 0

        def init_stream_yield_batches():
            should_write_start_length = True
            # For cogroup, iterator is Iterator[[(df, arrow_type)]]
            # Flatten: Iterator[[(df, arrow_type)]] -> Iterator[(df, arrow_type)]
            frames = (item for batch in iterator for item in batch)
            # Apply slicing to each (df, arrow_type)
            slices = (slice_pandas_frame(iter([frame_tuple]), self.max_bytes) for frame_tuple in frames)
            slices = itertools.chain(*itertools.chain(*slices))

            def create_batch(sliced):
                df, spark_type = sliced
                schema = StructType([StructField("_0", spark_type)])
                return PandasToArrowConversion.convert(
                    [df],
                    schema,
                    timezone=self._timezone,
                    safecheck=self._safecheck,
                    arrow_cast=self._arrow_cast,
                    prefers_large_types=self._prefers_large_types,
                    assign_cols_by_name=self._assign_cols_by_name,
                    int_to_decimal_coercion_enabled=self._int_to_decimal_coercion_enabled,
                )

            batches = (create_batch(sliced) for sliced in slices)
            for batch in batches:
                if should_write_start_length:
                    write_int(SpecialLengths.START_ARROW_STREAM, stream)
                    should_write_start_length = False
                yield batch

        return ArrowStreamSerializer.dump_stream(
            self,
            init_stream_yield_batches(),
            stream,
            timely_flush_enabled=self.timely_flush_enabled,
            timely_flush_timeout_ms=self.timely_flush_timeout_ms,
        )
